-- Optional HANA SQL objects for reporting
CREATE COLUMN TABLE "@TF_LC_AUD" (
  "DocEntry" INTEGER GENERATED BY DEFAULT AS IDENTITY,
  "LcCode" NVARCHAR(30),
  "Action" NVARCHAR(20),
  "ActionDate" SECONDDATE,
  "UserSign" INTEGER
);

CREATE COLUMN TABLE "@TF_BG_AUD" (
  "DocEntry" INTEGER GENERATED BY DEFAULT AS IDENTITY,
  "BgCode" NVARCHAR(30),
  "Action" NVARCHAR(20),
  "ActionDate" SECONDDATE,
  "UserSign" INTEGER
);
